#!/bin/bash
set -e

curl -fsSL https://get.docker.com | sh

mkdir -p /opt/remnanode
cd /opt/remnanode

cat > docker-compose.yml <<'EOF'
services:
  remnanode:
    container_name: remnanode
    hostname: remnanode
    image: remnawave/node:latest
    network_mode: host
    restart: always
    cap_add:
      - NET_ADMIN
    ulimits:
      nofile:
        soft: 1048576
        hard: 1048576
    environment:
      - NODE_PORT=2222
      - SECRET_

docker compose up -d
docker compose logs -f -t
